(function(w){"use strict";const ID="power-formula";function compute(x){const wv=Number(x.work),t=Number(x.time);if(!Number.isFinite(wv)||!Number.isFinite(t)||t<=0)return{error:"에너지와 0보다 큰 시간을 입력해 주세요."};return{value:wv/t};}
function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>일·에너지 (J)</label><input class="hm-calc-input" inputmode="decimal" data-key="work" placeholder="" value=""></div><div class="hm-calc-field"><label>시간 (s)</label><input class="hm-calc-input" inputmode="decimal" data-key="time" placeholder="" value=""></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const inputs=Array.prototype.slice.call(root.querySelectorAll("input[data-key]")),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const x={};inputs.forEach(i=>x[i.dataset.key]=api.parseNumber(i.value));const r=compute(x);if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("일률",`${api.formatNumber(r.value,8)} W`,"P = W ÷ t"));});}
w.HM_CALC.register(ID,{compute,render});})(window);
